INSERT INTO questions (id, specialty, category, domain_name, subtopic, difficulty, stem, choices, correct_answer, explanation, "references", status, telemetry) VALUES
('authored-batch-r3-001', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Burn injury: succinylcholine-induced hyperkalemia and receptor upregulation', 'medium', 'A 34-year-old man is brought to the OR for serial excision and grafting of deep partial- and full-thickness flame burns covering 40% of his total body surface area. The injury occurred 12 days ago. He is hemodynamically stable on the ventilator and requires a brief deepening of anesthesia for line placement before grafting. The trainee asks for succinylcholine 1.5 mg/kg to facilitate a quick intubating-level relaxation. Shortly after a similar dose was given at an outside facility yesterday, the patient reportedly developed a wide-complex tachyarrhythmia. Which of the following best explains why succinylcholine is contraindicated in this patient at this time?', '[{"text":"Upregulation of extrajunctional (immature) acetylcholine receptors causes exaggerated potassium efflux and life-threatening hyperkalemia","label":"A","correct":true,"rationale":"Correct: after the first 24-48 hours, burns trigger proliferation of extrajunctional/fetal-type nicotinic receptors across the muscle membrane, so depolarization by succinylcholine releases a massive, potentially fatal potassium load."},{"text":"Burn-induced pseudocholinesterase deficiency markedly prolongs the duration of succinylcholine-induced paralysis","label":"B","correct":false,"rationale":"Incorrect: although plasma cholinesterase activity can fall with burns, prolonged block is not the lethal mechanism, and a modestly longer paralysis does not explain an acute malignant arrhythmia."},{"text":"Thermal injury sensitizes the myocardium so that the muscarinic effects of succinylcholine precipitate refractory bradyarrhythmias","label":"C","correct":false,"rationale":"Incorrect: succinylcholine can cause bradycardia (especially in children or with repeat dosing), but the described wide-complex tachyarrhythmia in a burn patient points to hyperkalemia, not a vagal effect."},{"text":"Burn patients reliably exhibit increased sensitivity to succinylcholine, so a standard dose produces a profound, unterminating block","label":"D","correct":false,"rationale":"Incorrect: burn patients are actually resistant to nondepolarizing agents from the same receptor upregulation, and the danger of succinylcholine is hyperkalemia, not an unusually deep or unterminating block."},{"text":"Succinylcholine triggers malignant hyperthermia in burn patients because thermal injury unmasks a latent RYR1 channelopathy","label":"E","correct":false,"rationale":"Incorrect: burns do not create malignant hyperthermia susceptibility, which is an inherited RYR1/CACNA1S trait unrelated to the acquired receptor changes of thermal injury."}]'::jsonb, 'A', 'Within hours of a major burn, denervation-type changes drive widespread upregulation of extrajunctional (immature/fetal-subtype) acetylcholine receptors. When succinylcholine depolarizes these receptors across the entire muscle membrane rather than just the endplate, the resulting potassium efflux can produce hyperkalemic cardiac arrest. The risk is minimal in the first ~48 hours but climbs sharply from about days 7-10 and can persist for up to 1-2 years until receptor populations normalize, so a nondepolarizing relaxant (e.g., rocuronium) should be used instead.', '[{"url":"https://www.openanesthesia.org/keywords/succinylcholine/","source":"Succinylcholine - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-002', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Inhalation injury: carbon monoxide poisoning and pulse oximetry limitations', 'easy', 'A 52-year-old man is rescued from a house fire and arrives obtunded with soot around the nares, singed nasal hairs, and a hoarse voice. He is breathing spontaneously on a non-rebreather mask. Vitals: HR 118, BP 138/84, RR 26, SpO2 99% on the pulse oximeter. He complains of severe headache and nausea and is intermittently confused. An arterial blood gas shows pH 7.30 with a normal PaO2 but a measured carboxyhemoglobin of 28%. Which statement best explains the discrepancy between his oximetry reading and his clinical condition, and the correct next step?', '[{"text":"The normal PaO2 confirms adequate tissue oxygen delivery, so observation alone on room air is appropriate once he is more alert","label":"A","correct":false,"rationale":"Incorrect: PaO2 reflects dissolved oxygen, not the oxygen-carrying capacity crippled by carboxyhemoglobin, so a normal PaO2 is misleading and observation on room air would prolong a dangerous CO half-life."},{"text":"Standard pulse oximetry cannot distinguish carboxyhemoglobin from oxyhemoglobin, so the SpO2 is falsely reassuring; he needs high-flow 100% oxygen","label":"B","correct":true,"rationale":"Correct: a conventional two-wavelength oximeter reads carboxyhemoglobin much like oxyhemoglobin and overestimates true saturation, so high-flow 100% oxygen (and consideration of hyperbaric therapy) is required to accelerate CO elimination."},{"text":"The high SpO2 indicates methemoglobinemia, which is best treated with intravenous methylene blue","label":"C","correct":false,"rationale":"Incorrect: methemoglobinemia classically drives SpO2 toward roughly 85%, and the measured carboxyhemoglobin identifies CO poisoning, for which methylene blue is not indicated."},{"text":"His symptoms are explained by cyanide toxicity alone, so 100% oxygen has no role and hydroxocobalamin should replace it","label":"D","correct":false,"rationale":"Incorrect: although concomitant cyanide toxicity can occur in enclosed-space fires, the documented carboxyhemoglobin of 28% mandates 100% oxygen, which is foundational therapy and is not replaced by hydroxocobalamin."},{"text":"The pulse oximeter is malfunctioning from motion and poor perfusion, so a finger rewarming maneuver will correct the reading","label":"E","correct":false,"rationale":"Incorrect: the reading is not an artifact of perfusion or motion but a predictable limitation of conventional oximetry in the presence of carboxyhemoglobin, which rewarming cannot fix."}]'::jsonb, 'B', 'Carboxyhemoglobin absorbs light similarly to oxyhemoglobin at the wavelengths used by conventional pulse oximeters, so the SpO2 can read near-normal despite severe impairment of oxygen-carrying capacity. Diagnosis requires direct co-oximetry measurement of carboxyhemoglobin, and PaO2 stays normal because it reflects only dissolved oxygen. Treatment is immediate high-flow 100% oxygen by non-rebreather (or via the ventilator), which shortens the CO half-life dramatically; hyperbaric oxygen is considered for severe poisoning such as neurologic impairment or very high carboxyhemoglobin levels.', '[{"url":"https://www.openanesthesia.org/keywords/carbon-monoxide-poisoning/","source":"Carbon Monoxide Poisoning - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-003', 'Trauma, Burns & Critical Events', 'Trauma, Burns & Critical Events', 'Subspecialty Care', 'Critical events: intraoperative venous air embolism detection and management', 'hard', 'A 58-year-old woman is undergoing a posterior fossa craniotomy in the sitting position under general anesthesia with controlled ventilation. About 90 minutes into the case, while the surgeon is working near a large dural venous sinus, the capnograph shows an abrupt drop in end-tidal CO2 from 34 to 19 mmHg, the SpO2 begins to fall, and the blood pressure declines from 118/70 to 82/48 mmHg. A precordial Doppler probe emits a sudden roaring/''mill-wheel'' change in tone. Which of the following is the most appropriate immediate action?', '[{"text":"Increase the inspired nitrous oxide concentration to maintain anesthetic depth while the surgeon controls the field","label":"A","correct":false,"rationale":"Incorrect: nitrous oxide diffuses into and expands entrained air bubbles, enlarging the embolus, so it must be discontinued rather than increased."},{"text":"Administer a fluid bolus and deepen anesthesia with additional volatile agent, then reassess in 10 minutes before acting further","label":"B","correct":false,"rationale":"Incorrect: a 10-minute delay during an ongoing air embolism is dangerous, and deepening volatile anesthetic does not stop air entrainment or address the hemodynamic collapse."},{"text":"Notify the surgeon to flood the surgical field with saline and stop air entry, discontinue nitrous oxide, and give 100% oxygen","label":"C","correct":true,"rationale":"Correct: the first priorities are halting further air entrainment (flood the field, occlude the open vessel, lower the head) while removing nitrous oxide and delivering 100% oxygen to support oxygenation and shrink the existing bubble."},{"text":"Immediately convert the patient to the reverse Trendelenburg (further head-up) position to encourage the air to rise out of the wound","label":"D","correct":false,"rationale":"Incorrect: head-up positioning keeps the operative site above the heart and promotes continued air entrainment, whereas the patient should be moved toward head-down/left-lateral to reduce further entry."},{"text":"Begin chest compressions and prepare for emergent sternotomy regardless of the rhythm, since air embolism mandates open cardiac massage","label":"E","correct":false,"rationale":"Incorrect: the patient still has a perfusing rhythm with a measurable blood pressure, so reflexive chest compressions and sternotomy are not the immediate step; source control and 100% oxygen come first."}]'::jsonb, 'C', 'A sudden fall in end-tidal CO2 with hemodynamic deterioration and a ''mill-wheel'' Doppler change during a sitting craniotomy is classic for venous air embolism, which occurs when the operative site sits above the level of the heart and air is entrained into open venous channels. The immediate response is to stop further air entry (alert the surgeon to flood the field and occlude the vessel, lower the head), discontinue nitrous oxide because it expands the air bubble, deliver 100% oxygen, and support the circulation with fluids and vasopressors; aspiration through a right-atrial catheter may also be attempted. Transesophageal echocardiography is the most sensitive intraoperative monitor for detecting entrained air.', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-004', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'One-lung ventilation: management of intraoperative hypoxemia', 'medium', 'A 64-year-old man with a 50-pack-year smoking history is undergoing a right upper lobectomy via right thoracotomy. A left-sided double-lumen tube is placed and confirmed by fiberoptic bronchoscopy. Twenty minutes after initiating one-lung ventilation of the dependent left lung with an FiO2 of 1.0, the SpO2 drifts from 98% to 84%. Peak airway pressures are unchanged, the capnogram is normal, and bilateral breath sounds over the dependent lung are clear. The surgeon is mid-dissection at the hilum and asks for one more minute. Which intervention is the most appropriate next step to improve oxygenation while permitting the surgeon to continue?', '[{"text":"Immediately deflate the bronchial cuff and resume two-lung ventilation","label":"A","correct":false,"rationale":"Incorrect: this is the definitive rescue for refractory or severe desaturation but fully re-expands the operative lung and halts surgery, which is not yet required when a graded measure can be tried first."},{"text":"Add 10 cm H2O of PEEP to the dependent ventilated lung alone","label":"B","correct":false,"rationale":"Incorrect: PEEP to the dependent lung can help recruit atelectasis but may also overdistend alveoli and divert blood flow toward the nonventilated lung, worsening shunt, so it is less reliably beneficial as a first maneuver than nondependent CPAP."},{"text":"Decrease the FiO2 to 0.6 to limit absorption atelectasis","label":"C","correct":false,"rationale":"Incorrect: lowering FiO2 during active hypoxemia reduces the alveolar oxygen available for the dependent lung and would deepen, not relieve, the desaturation."},{"text":"Apply 5-10 cm H2O of CPAP with oxygen to the nonventilated (operative) right lung","label":"D","correct":true,"rationale":"Correct: applying low-level CPAP to the collapsed nondependent lung oxygenates blood passing through it via residual perfusion without fully re-expanding the surgical field, addressing shunt while letting dissection continue."},{"text":"Administer a fluid bolus and start a phenylephrine infusion to raise cardiac output","label":"E","correct":false,"rationale":"Incorrect: the problem is intrapulmonary shunt, not hypovolemia, and raising perfusion to the nonventilated lung with vasoconstrictors that blunt hypoxic pulmonary vasoconstriction can worsen the shunt fraction."}]'::jsonb, 'D', 'Hypoxemia during one-lung ventilation is driven by transpulmonary shunt through the deliberately collapsed nondependent lung. After confirming tube position and FiO2 of 1.0, a graded response is appropriate: CPAP to the nonventilated lung is the classic next step because oxygen reaching residually perfused alveoli reduces shunt with minimal disruption of the surgical field. Reserve full two-lung ventilation for severe or refractory desaturation. Dependent-lung PEEP helps recruitment but can redistribute flow and is less consistently effective as the initial maneuver.', '[{"url":"https://www.openanesthesia.org/keywords/hypoxia-during-one-lung-ventilation/","source":"Hypoxia During One-Lung Ventilation - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-005', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'Vascular surgery: aortic cross-clamp hemodynamic physiology', 'medium', 'A 71-year-old man undergoes open repair of an infrarenal abdominal aortic aneurysm. His baseline blood pressure is 138/80 mmHg. Immediately after the surgeon applies the infrarenal aortic cross-clamp, the radial arterial line shows a rise to 192/104 mmHg, central venous pressure increases, and the anesthesiologist notes a widening gap between the arterial and end-tidal CO2. Which physiologic change most directly explains the abrupt rise in arterial blood pressure seen at this moment?', '[{"text":"Reflex bradycardia-mediated increase in stroke volume from the baroreceptor response","label":"A","correct":false,"rationale":"Incorrect: any reflex bradycardia is a downstream response to the hypertension rather than its cause, and it does not generate the pressure rise itself."},{"text":"Release of vasodilatory metabolites from ischemic tissue distal to the clamp","label":"B","correct":false,"rationale":"Incorrect: ischemic metabolite washout causes hypotension and vasodilation at unclamping, the opposite of the hypertension seen immediately after clamp application."},{"text":"Catecholamine surge from inadequate anesthetic depth at the time of clamping","label":"C","correct":false,"rationale":"Incorrect: although light anesthesia can raise pressure, the predictable, mechanically timed hypertension that accompanies clamping is explained by afterload, not by anesthetic depth."},{"text":"Renin-angiotensin activation producing immediate angiotensin II vasoconstriction","label":"D","correct":false,"rationale":"Incorrect: renin-angiotensin activation contributes to later humoral effects but operates over minutes and is not the immediate mechanism of the instantaneous pressure rise."},{"text":"An acute increase in left ventricular afterload from the rise in systemic vascular resistance","label":"E","correct":true,"rationale":"Correct: occluding the aorta abruptly raises impedance to ejection, increasing systemic vascular resistance and afterload, which is the principal driver of the hypertension that follows cross-clamping."}]'::jsonb, 'E', 'Aortic cross-clamping abruptly increases impedance to left ventricular ejection, raising systemic vascular resistance and afterload; this mechanical change is the dominant cause of the hypertension seen immediately after the clamp is applied. Blood volume also redistributes proximally, raising preload, and the magnitude depends on clamp level (greater with supraceliac than infraceliac). Humoral effects such as renin-angiotensin activation and catecholamine release evolve over the following minutes, and ischemic metabolite washout produces the hypotension characteristic of unclamping.', '[{"url":"https://www.openanesthesia.org/keywords/aortic-cross-clamping/","source":"Aortic Cross-Clamping - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-006', 'Thoracic & Vascular', 'Thoracic & Vascular', 'Subspecialty Care', 'Carotid endarterectomy: cerebral oximetry/NIRS neuromonitoring', 'hard', 'A 68-year-old woman with hypertension and a 90% left internal carotid stenosis undergoes carotid endarterectomy under general anesthesia. Cerebral regional oxygen saturation is monitored bilaterally with near-infrared spectroscopy (NIRS). Baseline left-sided rSO2 is 68%. Shortly after the surgeon applies the carotid cross-clamp, the left rSO2 falls to 55% while the right side and all other vital signs, including mean arterial pressure of 82 mmHg and normocapnia, remain unchanged. Which response is the most appropriate next step?', '[{"text":"Communicate the ipsilateral desaturation to the surgeon and support placement of an intraluminal shunt while raising the blood pressure","label":"A","correct":true,"rationale":"Correct: an isolated ipsilateral NIRS decline after clamping signals inadequate collateral perfusion, and the appropriate response is to alert the surgeon for possible shunt placement while augmenting blood pressure to improve collateral flow."},{"text":"Continue observation, because a drop of this magnitude is within normal variation and does not indicate ischemia","label":"B","correct":false,"rationale":"Incorrect: a relative decline of roughly 19% from baseline approaches the threshold associated with cerebral ischemia and warrants action rather than passive observation."},{"text":"Lower the mean arterial pressure to reduce embolic risk across the operative field","label":"C","correct":false,"rationale":"Incorrect: deliberately lowering pressure would further reduce collateral cerebral perfusion through the circle of Willis and worsen the ipsilateral desaturation."},{"text":"Deepen anesthesia with additional volatile agent to lower cerebral metabolic demand","label":"D","correct":false,"rationale":"Incorrect: while reducing metabolic rate has theoretical appeal, volatile agents cause vasodilation and hypotension that can compromise collateral flow, and this does not address the perfusion deficit as directly as restoring flow."},{"text":"Increase the FiO2 to 1.0 to raise arterial oxygen content","label":"E","correct":false,"rationale":"Incorrect: arterial oxygenation is already adequate and raising FiO2 does little for a regional saturation drop caused by reduced perfusion rather than reduced arterial oxygen content."}]'::jsonb, 'A', 'During carotid endarterectomy, an isolated ipsilateral fall in NIRS cerebral oximetry after cross-clamping reflects inadequate collateral perfusion through the circle of Willis, and a relative decline near 20% from baseline is the reported threshold linked to acute cerebral ischemia. The correct response is to communicate with the surgeon to support shunt placement and to augment collateral flow by raising blood pressure toward or above baseline, not to lower pressure or simply observe. NIRS is one of several monitors (alongside EEG, evoked potentials, and awake neurologic exam) used to detect clamp-related ischemia.', '[{"url":"https://www.openanesthesia.org/keywords/cerebral-oximetry-and-near-infrared-spectroscopy/","source":"Cerebral Oximetry and Near Infrared Spectroscopy - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-007', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Pharmacokinetics: context-sensitive half-time of intravenous infusions', 'medium', 'A 78-year-old man (110 kg, BMI 38) with obstructive sleep apnea, an EF of 35%, and chronic kidney disease (eGFR 28 mL/min) undergoes a 6-hour open abdominal aortic aneurysm repair. Anesthesia is maintained with a propofol infusion plus a continuous remifentanil infusion at 0.2 mcg/kg/min. The surgeon places the final fascial suture and the team plans an awake, extubated emergence. The remifentanil infusion is discontinued. Compared with discontinuing a fentanyl infusion that had run for the same duration, what is the expected behavior of the plasma remifentanil concentration after the infusion is stopped?', '[{"text":"It will decline slowly because hepatic clearance of remifentanil is markedly reduced by the patient''s low cardiac output","label":"A","correct":false,"rationale":"Incorrect: remifentanil clearance depends on widespread ester hydrolysis rather than hepatic blood flow, so a low ejection fraction does not meaningfully prolong its offset."},{"text":"It will decrease rapidly with a context-sensitive half-time of roughly 3-4 minutes, essentially independent of infusion duration","label":"B","correct":true,"rationale":"Correct: remifentanil is cleared by nonspecific plasma and tissue esterases, so it does not accumulate and its context-sensitive half-time stays near 3-4 minutes regardless of how long it was infused."},{"text":"It will be prolonged relative to fentanyl because the patient''s renal impairment causes accumulation of remifentanil","label":"C","correct":false,"rationale":"Incorrect: although the carboxylic acid metabolite is renally excreted and accumulates, it is essentially inactive, so renal failure does not prolong remifentanil''s clinical offset."},{"text":"It will mirror fentanyl, since both opioids have a context-sensitive half-time that lengthens substantially with longer infusions","label":"D","correct":false,"rationale":"Incorrect: fentanyl''s context-sensitive half-time lengthens markedly with infusion duration because of peripheral tissue accumulation, whereas remifentanil''s does not."},{"text":"It will decrease faster than fentanyl only if naloxone is co-administered to displace it from peripheral compartments","label":"E","correct":false,"rationale":"Incorrect: remifentanil''s rapid offset is intrinsic to its esterase metabolism and requires no antagonist, and naloxone would not change its pharmacokinetics."}]'::jsonb, 'B', 'Context-sensitive half-time is the time for plasma drug concentration to fall by 50% after stopping a continuous infusion, and it depends on both the duration of infusion and the drug''s distribution and clearance. Remifentanil is metabolized by nonspecific plasma and tissue esterases, so it does not accumulate in peripheral tissues and its context-sensitive half-time remains roughly 3-4 minutes even after prolonged infusions. This duration-independent, organ-independent offset makes it predictable in patients with hepatic, renal, or cardiac compromise, in contrast to fentanyl, whose context-sensitive half-time grows substantially with longer infusions.', '[{"url":"https://www.openanesthesia.org/keywords/context-sensitive-half-time/","source":"Context-Sensitive Half-Time (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-008', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Local anesthetics: systemic toxicity (LAST) and lipid emulsion rescue', 'easy', 'A 24-year-old woman (60 kg) is having an ultrasound-guided interscalene brachial plexus block placed for shoulder arthroscopy. Approximately two minutes after injection of 30 mL of 0.5% bupivacaine, she reports perioral numbness and tinnitus, then becomes agitated and has a generalized tonic-clonic seizure followed by bradycardia and a widened QRS on the monitor. The seizure is terminated with midazolam and the airway is secured. After calling for help and the lipid emulsion kit, which intervention is the most important specific therapy for this patient''s condition?', '[{"text":"Administer a high-dose epinephrine bolus of 1 mg IV per standard ACLS dosing","label":"A","correct":false,"rationale":"Incorrect: in local anesthetic systemic toxicity, large epinephrine boluses can worsen arrhythmias and impair resuscitation, so reduced doses (≤ 1 mcg/kg) are recommended."},{"text":"Administer intralipid only if cardiac arrest occurs, withholding it while a pulse is present","label":"B","correct":false,"rationale":"Incorrect: lipid emulsion should be started at the first sign of serious toxicity such as seizures or cardiovascular instability, not delayed until arrest."},{"text":"Give a 20% lipid emulsion bolus of approximately 1.5 mL/kg over 1 minute, then start an infusion","label":"C","correct":true,"rationale":"Correct: 20% lipid emulsion is the specific antidote for local anesthetic systemic toxicity, dosed as a 1.5 mL/kg bolus followed by an infusion to create a lipid sink and support cardiac energetics."},{"text":"Give intravenous flumazenil to reverse the midazolam and clarify the cause of the seizure","label":"D","correct":false,"rationale":"Incorrect: flumazenil does not treat local anesthetic toxicity and could lower the seizure threshold further in a patient already convulsing from bupivacaine."},{"text":"Administer a calcium chloride bolus to stabilize the myocardium against the widened QRS","label":"E","correct":false,"rationale":"Incorrect: calcium does not reverse bupivacaine-induced sodium channel blockade and is not part of the local anesthetic systemic toxicity protocol."}]'::jsonb, 'C', 'Local anesthetic systemic toxicity (LAST) classically progresses from neurologic excitation (perioral numbness, tinnitus, agitation, seizures) to cardiovascular collapse, and bupivacaine is particularly cardiotoxic because of its avid, slow-dissociating sodium channel blockade. Twenty percent lipid emulsion is the specific therapy: a bolus of about 1.5 mL/kg lean body weight over 1 minute followed by an infusion of roughly 0.25 mL/kg/min. Lipid should be given early at the first signs of serious toxicity, alongside airway management, seizure control, and modified ACLS using reduced epinephrine doses and avoidance of vasopressin, calcium channel blockers, and local anesthetic antiarrhythmics.', '[{"url":"https://www.openanesthesia.org/keywords/local-anesthetic-systemic-toxicity/","source":"Local Anesthetic Systemic Toxicity (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-009', 'Pharmacology', 'Pharmacology', 'Subspecialty Care', 'Inhalational and neuromuscular agents: malignant hyperthermia and dantrolene', 'medium', 'A previously healthy 19-year-old man undergoes general anesthesia for an open reduction of a tibial fracture. Anesthesia is induced with propofol and rocuronium and maintained with sevoflurane. About 40 minutes into the case the anesthesia care team notes an unexplained rise in end-tidal CO2 to 68 mmHg despite increased minute ventilation, sinus tachycardia, generalized muscle rigidity, and a temperature climbing from 37.2°C to 39.8°C. Malignant hyperthermia is suspected. After discontinuing the volatile agent, hyperventilating with 100% oxygen, and converting to a nontriggering technique, what is the most important specific pharmacologic treatment?', '[{"text":"Give a beta-blocker such as esmolol to control the tachycardia and reduce metabolic demand","label":"A","correct":false,"rationale":"Incorrect: a beta-blocker treats only the heart rate and does not address the underlying skeletal muscle hypermetabolism that defines the crisis."},{"text":"Administer a benzodiazepine infusion to relax the rigid skeletal muscles","label":"B","correct":false,"rationale":"Incorrect: benzodiazepines act centrally and cannot reverse the ryanodine-receptor-mediated calcium release responsible for the sustained muscle rigidity."},{"text":"Give an additional dose of a nondepolarizing neuromuscular blocker to abolish the rigidity","label":"C","correct":false,"rationale":"Incorrect: the rigidity arises from intracellular calcium dysregulation distal to the neuromuscular junction, so neuromuscular blockers do not relieve it."},{"text":"Administer intravenous dantrolene 2.5 mg/kg, repeated as needed until signs of hypermetabolism resolve","label":"D","correct":true,"rationale":"Correct: dantrolene is the only specific treatment for malignant hyperthermia, started at 2.5 mg/kg IV and repeated until end-tidal CO2, rigidity, and temperature improve, because it blocks pathologic calcium release from the ryanodine receptor."},{"text":"Administer sodium bicarbonate as the primary therapy to correct the metabolic acidosis","label":"E","correct":false,"rationale":"Incorrect: bicarbonate is supportive for severe acidosis but does not treat the cause, and without dantrolene the hypermetabolism continues."}]'::jsonb, 'D', 'Malignant hyperthermia is a syndrome of skeletal muscle hypermetabolism triggered by volatile anesthetics and succinylcholine in genetically susceptible patients, usually from a ryanodine receptor (RYR1) mutation. Early signs include an unexplained rise in end-tidal CO2, tachycardia, masseter or generalized rigidity, and a later rise in temperature. Management is to stop triggering agents, hyperventilate with 100% oxygen, and give dantrolene 2.5 mg/kg IV repeated until the hypermetabolic signs abate, while treating hyperkalemia, acidosis, and arrhythmias and cooling the patient.', '[{"url":"https://www.openanesthesia.org/keywords/malignant-hyperthermia/","source":"Malignant Hyperthermia (OpenAnesthesia)"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-010', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Operating room / airway fire during laser airway surgery', 'medium', 'A 58-year-old man with early glottic squamous cell carcinoma is undergoing CO2 laser excision of a vocal cord lesion under general anesthesia via a laser-resistant endotracheal tube. During the case, the surgeon activates the laser and a flash with flame is immediately seen at the surgical field within the airway. Which of the following is the MOST appropriate FIRST action?', '[{"text":"Disconnect the breathing circuit but leave the tube in place to protect the airway","label":"A","correct":false,"rationale":"Incorrect: leaving the ignited tube in place allows it to continue burning and injuring the airway, so it must be removed, not retained."},{"text":"Reduce the FiO2 to 0.30 and continue the case once the flame self-extinguishes","label":"B","correct":false,"rationale":"Incorrect: merely lowering FiO2 does not address the actively burning tube and delays the definitive step of stopping gas flow and removing it."},{"text":"Flood the surgical field with saline before addressing the breathing circuit","label":"C","correct":false,"rationale":"Incorrect: pouring saline is a useful adjunct after the tube is removed, but stopping gas flow and removing the tube must come first to halt the fire."},{"text":"Administer a bolus of intravenous dexamethasone and racemic epinephrine","label":"D","correct":false,"rationale":"Incorrect: steroids and nebulized epinephrine address later airway edema but do nothing to extinguish an active fire that is causing ongoing thermal injury."},{"text":"Stop the flow of all airway gases and remove the endotracheal tube","label":"E","correct":true,"rationale":"Correct: the first priority in an airway fire is to immediately stop ventilation (cut off the oxidizer) and remove the burning endotracheal tube, which is both fuel and a conduit for the fire."}]'::jsonb, 'E', 'In an airway fire, the immediate response is to simultaneously stop the flow of airway gases (removing the oxidizer) and remove the endotracheal tube (removing the fuel and ignition conduit); only then is the field flooded with saline and the airway re-evaluated. Prevention centers on using the lowest feasible FiO2, avoiding nitrous oxide, and using a laser-resistant tube with a saline-filled cuff. After extinguishing the fire, the patient should be re-intubated, the airway inspected via bronchoscopy for thermal injury, and supportive care provided.', '[{"url":"https://www.openanesthesia.org/keywords/surgical-fires/","source":"Surgical Fires - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-011', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Pediatric ENT emergency / post-tonsillectomy hemorrhage', 'medium', 'A 4-year-old, 18-kg girl is brought to the operating room 7 hours after adenotonsillectomy with active bleeding from the tonsillar fossa. She has swallowed blood, is tachycardic at 150/min, has cool extremities and capillary refill of 3 seconds, and is anxious. Hemoglobin is 9.1 g/dL. The surgeon plans urgent control of the bleeding. Which of the following is the MOST appropriate anesthetic approach?', '[{"text":"Volume resuscitation followed by rapid sequence induction with a styletted tube and suction ready","label":"A","correct":true,"rationale":"Correct: the child is hypovolemic with a stomach full of blood, so isotonic fluid resuscitation before a rapid sequence induction with two working suctions and a styletted tube optimizes hemodynamics and protects against aspiration."},{"text":"Inhalational induction with sevoflurane while maintaining spontaneous ventilation","label":"B","correct":false,"rationale":"Incorrect: a slow inhalational induction in a hypovolemic child with a full stomach of blood markedly increases aspiration risk and risks hemodynamic collapse from vasodilation."},{"text":"Awake fiberoptic intubation under topical anesthesia","label":"C","correct":false,"rationale":"Incorrect: awake fiberoptic intubation is impractical and poorly tolerated in a frightened young child with active oropharyngeal bleeding that obscures the view."},{"text":"Proceed immediately with induction without intravenous access, placing an IV after the airway is secured","label":"D","correct":false,"rationale":"Incorrect: inducing a hypovolemic, actively bleeding child without IV access removes the ability to resuscitate or treat hypotension during a high-risk induction."},{"text":"Deep extubation at the end of the case to avoid coughing and re-bleeding","label":"E","correct":false,"rationale":"Incorrect: this child is at high aspiration risk from swallowed blood, so she should be fully awake with protective reflexes before extubation, not extubated deep."}]'::jsonb, 'A', 'A child with post-tonsillectomy hemorrhage is often hypovolemic, anemic, and has a stomach full of swallowed blood, creating combined risks of hemodynamic instability and aspiration. Management priorities are establishing IV access, resuscitating with 10-20 mL/kg isotonic crystalloid, preparing two suctions and multiple laryngoscopy tools, and performing a rapid sequence induction. Because of the aspiration risk, the trachea should be extubated only when the child is fully awake with intact airway reflexes.', '[{"url":"https://www.openanesthesia.org/keywords/posttonsillectomy-hemorrhage/","source":"Posttonsillectomy Hemorrhage - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-012', 'Airway & ENT', 'Airway & ENT', 'Subspecialty Care', 'Deep neck space infection / difficult airway (Ludwig angina)', 'hard', 'A 52-year-old man with poorly controlled diabetes presents with a 2-day history of a swollen, tender, indurated submandibular region, trismus, drooling, a muffled "hot potato" voice, and an elevated, displaced tongue after a recent dental infection. He is sitting upright, leaning forward, with mild stridor and an oxygen saturation of 93% on room air. He requires general anesthesia for incision and drainage. Which of the following is the MOST appropriate plan for securing the airway?', '[{"text":"Standard intravenous rapid sequence induction with rocuronium and direct laryngoscopy","label":"A","correct":false,"rationale":"Incorrect: inducing apnea and paralysis in a patient with severe floor-of-mouth edema and trismus risks complete airway loss with an unintubatable, unmaskable airway."},{"text":"Awake fiberoptic intubation with topicalization and a surgeon prepared for emergency tracheostomy","label":"B","correct":true,"rationale":"Correct: maintaining spontaneous ventilation via awake fiberoptic intubation while preserving the patient''s own airway tone, with surgical airway backup immediately available, is the safest approach in Ludwig angina."},{"text":"Inhalational induction with sevoflurane followed by direct laryngoscopy once deep","label":"C","correct":false,"rationale":"Incorrect: inhalational induction is unreliable in a distorted, swollen airway and can precipitate total obstruction once muscle tone is lost."},{"text":"Placement of a supraglottic airway device after a small dose of propofol","label":"D","correct":false,"rationale":"Incorrect: a supraglottic device cannot bypass supraglottic and floor-of-mouth swelling and does not protect against the rapidly progressive obstruction of Ludwig angina."},{"text":"Blind nasotracheal intubation without sedation","label":"E","correct":false,"rationale":"Incorrect: blind nasotracheal intubation in a distorted, edematous airway is likely to fail, cause bleeding, and worsen obstruction."}]'::jsonb, 'B', 'This patient has Ludwig angina, a rapidly progressive cellulitis of the submandibular, sublingual, and submental spaces that distorts the floor of the mouth and elevates the tongue, producing a potentially catastrophic difficult airway. The safest strategy preserves spontaneous ventilation through an awake technique such as awake fiberoptic intubation, with a surgeon scrubbed and ready for emergency tracheostomy. Induction of apnea or paralysis before the airway is secured risks a ''cannot intubate, cannot ventilate'' scenario.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK482354/","source":"Ludwig Angina - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-013', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Pheochromocytoma resection - preoperative adrenergic blockade sequencing', 'medium', 'A 44-year-old woman with episodic headaches, palpitations, and diaphoresis is found to have markedly elevated plasma free metanephrines and a 4-cm right adrenal mass consistent with pheochromocytoma. She is scheduled for laparoscopic adrenalectomy in 3 weeks. Her clinic blood pressure is 168/104 mmHg and heart rate is 96 beats/min. The surgical team asks how to begin pharmacologic optimization before the operation. Which approach is most appropriate to start her preoperative preparation?', '[{"text":"Begin metoprolol now to control her resting tachycardia, then add an alpha-blocker closer to surgery","label":"A","correct":false,"rationale":"Starting a beta-blocker first leaves alpha-mediated vasoconstriction unopposed, which can precipitate a severe hypertensive crisis and is explicitly contraindicated as the initial step."},{"text":"Start a calcium channel blocker as monotherapy and avoid alpha-blockade entirely to preserve intraoperative blood pressure lability","label":"B","correct":false,"rationale":"Calcium channel blockers are useful adjuncts or alternatives in selected patients, but routine preparation centers on alpha-blockade; relying on a calcium channel blocker alone is not the standard primary strategy and does not adequately control catecholamine-driven vasoconstriction."},{"text":"Start an alpha-adrenergic blocker such as phenoxybenzamine 10 to 14 days before surgery, adding a beta-blocker only after adequate alpha-blockade is established","label":"C","correct":true,"rationale":"Alpha-blockade begun roughly 10 to 14 days preoperatively controls vasoconstriction and allows intravascular volume to re-expand, and a beta-blocker is added only afterward to manage reflex tachycardia, making this the correct sequence."},{"text":"Proceed directly to surgery without medical preparation because laparoscopic resection minimizes catecholamine release","label":"D","correct":false,"rationale":"Tumor manipulation during any resection, including laparoscopic, can release massive catecholamine surges, so omitting preoperative blockade markedly increases the risk of intraoperative hypertensive crisis and is unacceptable."},{"text":"Restrict sodium and fluids in the days before surgery to blunt the expected intraoperative hypertension","label":"E","correct":false,"rationale":"These patients are chronically volume-contracted from catecholamine excess; fluid and sodium liberalization after alpha-blockade is encouraged, whereas restriction worsens the post-resection hypotension seen once catecholamine levels fall."}]'::jsonb, 'C', 'Catecholamine excess in pheochromocytoma produces chronic vasoconstriction and intravascular volume depletion. Alpha-adrenergic blockade started about 10 to 14 days preoperatively (classically phenoxybenzamine) relaxes the vasculature and allows the contracted plasma volume to re-expand, and only after this is achieved is a beta-blocker added to control reflex or residual tachycardia. Initiating beta-blockade first removes beta-2 mediated vasodilation while leaving alpha-mediated vasoconstriction unopposed, which can trigger a hypertensive crisis and acute heart failure. Adequate preparation, often confirmed by liberalized salt and fluid intake, blunts both the intraoperative catecholamine surge during tumor manipulation and the hypotension that follows ligation of the tumor''s venous drainage.', '[{"url":"https://www.openanesthesia.org/keywords/pheochromocytoma/","source":"Pheochromocytoma - OpenAnesthesia"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-014', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Diabetic ketoacidosis - perioperative electrolyte management before insulin', 'hard', 'A 22-year-old man with type 1 diabetes presents with a perforated appendix requiring urgent appendectomy. He is lethargic and breathing deeply. Labs show glucose 540 mg/dL, arterial pH 7.18, bicarbonate 9 mEq/L, an elevated anion gap with positive serum ketones, and serum potassium 3.1 mEq/L. The team is initiating treatment for diabetic ketoacidosis while preparing him for surgery. After starting aggressive isotonic crystalloid resuscitation, what is the most appropriate next step regarding insulin and potassium?', '[{"text":"Give an immediate IV insulin bolus and start an insulin infusion to rapidly close the anion gap, then replace potassium once it falls further","label":"A","correct":false,"rationale":"Insulin drives potassium intracellularly, so starting insulin while the serum potassium is already 3.1 mEq/L can precipitate life-threatening hypokalemia and arrhythmias, making this the dangerous wrong choice."},{"text":"Administer IV sodium bicarbonate to correct the acidosis first, which will raise the potassium and allow safe insulin dosing","label":"B","correct":false,"rationale":"Bicarbonate actually shifts potassium intracellularly and lowers serum potassium further, and it is not indicated at this pH, so it would worsen rather than solve the problem."},{"text":"Start the insulin infusion together with a dextrose-containing fluid now to prevent hypoglycemia, deferring potassium until later","label":"C","correct":false,"rationale":"Dextrose is added only once glucose falls to about 200 to 250 mg/dL, and starting insulin with this markedly low potassium still risks dangerous hypokalemia regardless of the dextrose."},{"text":"Withhold insulin and begin IV potassium replacement until the serum potassium exceeds 3.3 mEq/L, then start the insulin infusion","label":"D","correct":true,"rationale":"Because total body potassium is depleted in DKA and insulin shifts potassium into cells, insulin is held until the serum potassium is corrected above 3.3 mEq/L, after which the infusion can be safely started."},{"text":"Proceed to induction of general anesthesia immediately and manage the DKA entirely intraoperatively, since source control is the priority","label":"E","correct":false,"rationale":"When time allows, even with urgent surgery, initial resuscitation and correction of dangerous electrolyte and acid-base derangements should begin preoperatively because uncorrected hypokalemia and acidosis greatly increase the risk of intraoperative arrhythmias and instability."}]'::jsonb, 'D', 'In diabetic ketoacidosis, total body potassium is depleted even when the measured serum level appears normal or low, because acidosis and insulin deficiency shift potassium out of cells. Insulin reverses this shift and drives potassium intracellularly, so giving insulin when the serum potassium is already low (here 3.1 mEq/L) can cause profound hypokalemia and fatal arrhythmias. Standard practice is therefore to hold insulin and replace potassium until the serum level is at least 3.3 mEq/L, while aggressive isotonic fluid resuscitation continues; dextrose is added to the fluids only once glucose falls to roughly 200 to 250 mg/dL. For a patient needing urgent surgery, these derangements should be addressed before induction whenever the clinical timeline permits.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK534848/","source":"Ketoacidosis - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb),
('authored-batch-r3-015', 'Endocrine', 'Endocrine', 'Subspecialty Care', 'Thyroid storm - intraoperative recognition and treatment', 'medium', 'A 35-year-old woman with poorly controlled Graves disease undergoes emergency open reduction of an ankle fracture under general anesthesia, having had no time for medical optimization. Roughly 45 minutes into the case she develops a temperature of 40.1 C, heart rate of 165 beats/min in sinus tachycardia, blood pressure of 95/50 mmHg, and copious diaphoresis. End-tidal CO2 is mildly elevated but stable, and there is no masseter rigidity, no generalized muscular rigidity, and no rapid rise in end-tidal CO2. Which intervention most directly targets the underlying disorder?', '[{"text":"Administer dantrolene 2.5 mg/kg IV and discontinue all volatile anesthetic, treating this as malignant hyperthermia","label":"A","correct":false,"rationale":"The absence of rigidity, lack of an unexplained rapid rise in end-tidal CO2, and the clinical context of untreated Graves disease point away from malignant hyperthermia, so dantrolene does not target the actual disorder."},{"text":"Give a bolus of IV phenylephrine to support blood pressure and deepen anesthesia, then continue the case unchanged","label":"B","correct":false,"rationale":"This addresses only the hypotension and ignores the life-threatening thyrotoxic crisis, failing to treat the underlying catecholamine-sensitive hyperthyroid state."},{"text":"Treat with active surface cooling alone and defer pharmacologic therapy until thyroid function tests confirm the diagnosis","label":"C","correct":false,"rationale":"Thyroid storm is a clinical diagnosis requiring immediate treatment; waiting for confirmatory labs and using cooling alone delays the specific therapy needed to prevent death."},{"text":"Administer IV calcium chloride and sodium bicarbonate empirically to treat presumed hyperkalemic crisis","label":"D","correct":false,"rationale":"There is no evidence of hyperkalemia in this scenario, and this regimen does not address the thyrotoxic state that is driving the hyperthermia and tachycardia."},{"text":"Administer IV esmolol (or propranolol) to control the adrenergic response, give a thionamide such as propylthiouracil, and provide active cooling and supportive care","label":"E","correct":true,"rationale":"Beta-blockade blunts the dangerous adrenergic and hyperdynamic state, a thionamide blocks new thyroid hormone synthesis, and cooling plus supportive care round out the standard treatment of thyroid storm, directly targeting the disorder."}]'::jsonb, 'E', 'Intraoperative thyroid storm classically presents with marked hyperthermia, severe tachycardia, and hemodynamic changes in a patient with untreated or poorly controlled hyperthyroidism subjected to a stressor such as surgery, and it can mimic malignant hyperthermia. Key distinguishing features are the absence of muscular rigidity and the lack of a rapid, unexplained rise in end-tidal CO2 and severe acidosis that characterize malignant hyperthermia, along with the relevant endocrine history. Treatment is directed at the pathophysiology: a beta-blocker (esmolol or propranolol) to control the adrenergic surge, a thionamide such as propylthiouracil or methimazole to halt new hormone synthesis, and aggressive cooling with supportive care; iodine and corticosteroids are added in the full regimen. Dantrolene is reserved for true malignant hyperthermia and does not treat thyrotoxicosis.', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK448095/","source":"Thyroid Storm - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', '{}'::jsonb);
